import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = "http://localhost:5000";

function Login() {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const login = async () => {
    if (!username || !password) { setError("Please fill in all fields."); return; }
    setLoading(true);
    setError("");
    try {
      const res = await axios.post(`${API}/login`, { username, password });
      if (res.data.success) {
        localStorage.setItem("gym_admin", res.data.username);
        navigate("/dashboard");
      }
    } catch {
      setError("Invalid username or password.");
    }
    setLoading(false);
  };

  const handleKey = (e) => { if (e.key === "Enter") login(); };

  return (
    <div className="login-page">
      <div className="login-bg" />
      <div className="login-card">
        <h1>LOYD'S FITNESS<br />GYM</h1>
        <p className="subtitle">Admin Portal</p>

        {error && <div className="error-msg">{error}</div>}

        <div className="login-form">
          <input
            placeholder="Username"
            value={username}
            onChange={e => setUsername(e.target.value)}
            onKeyDown={handleKey}
            autoFocus
          />
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={e => setPassword(e.target.value)}
            onKeyDown={handleKey}
          />
          <button className="btn btn-primary" onClick={login} disabled={loading}>
            {loading ? "Signing in..." : "Sign In →"}
          </button>
        </div>

        <p style={{ marginTop: 24, fontSize: 11, color: "var(--muted)", textAlign: "center" }}>
          Default: admin / admin123
        </p>
      </div>
    </div>
  );
}

export default Login;
